import re
from flask import Flask, request, jsonify

app = Flask(__name__)

def validate_route_parameter(id):
    pattern = r'^\d{3}$'
    if re.match(pattern, id):
        return jsonify({ 'user_id': id })
    else:
        return jsonify({ 'error': 'Invalid route parameter' }), 400

@app.route('/users/<id>', methods=['GET'])
def get_user(id):
    return validate_route_parameter(id)

if __name__ == '__main__':
    app.run(port=3000)
